const cutoffMs = Date.now() - 30 * 86400 * 1000;
const SONIA_CHANNEL = 'UC_caIBdFY1E_KhlWamMkl9A';

function parseDate(s) {
  if (!s) return NaN;
  const abs = new Date(s).getTime();
  if (!Number.isNaN(abs)) return abs;
  const m = String(s).match(/(\d+)\s+(second|minute|hour|day|week|month|year)s?\s+ago/i);
  if (!m) return NaN;
  const f = { second: 1, minute: 60, hour: 3600, day: 86400, week: 604800, month: 2592000, year: 31536000 };
  return Date.now() - (+m[1]) * f[m[2].toLowerCase()] * 1000;
}

function sumViewsInWindow(allItems, requireChannelId) {
  const seen = new Set();
  let total = 0;
  for (const it of allItems) {
    const v = it.json;
    if (v.id && seen.has(v.id)) continue;
    if (v.id) seen.add(v.id);
    if (requireChannelId && v.channelId !== requireChannelId) continue;
    const t = parseDate(v.date);
    if (!Number.isNaN(t) && t < cutoffMs) continue;
    total += Number(v.viewCount ?? v.views ?? 0);
  }
  return total;
}

